INSERT INTO `question_table` (`q_no`, `question`, `Opt_one`, `Opt_two`, `Opt_three`, `Opt_four`, `Opt_five`, `set_num`, `correct_answer`) VALUES
(1, '<b> Find the unit digit in the product (4387)^245*(621)^72<br></b>', '1', '7', '2', '8', 'I am not attending this question', '1', 'B'),
(2, '<b> Sum of a fraction and thrice its reciprocal is 31/6.What is the fraction?</b>', '2/9', '9/4', '9/2', '4/9', 'I am not attending this question', '1', 'C'),
(3, '<b>  357:714::468:?</b>', '579', '417', '936', '864', 'I am not attending this question', '1', 'C'),
(4, '<b> If 16^24 divided by 17 ,the remainder is <br>', '1', '3', '4', '8', 'I am not attending this question', '1', 'A'),
(5, '<b> Find the sum of the first 50 odd numbers. <br>', '1600', '1900', '2500', '2900', 'I am not attending this question', '1', 'C'),
(6, '<b> A number whose one-fourth part is increased by 5 is equal to the third part diminished by 5.What is the number? <br></b>', '100', '80', '60', '120', 'I am not attending this question', '1', 'D'),
(7, '<b>If the number is divided by 3, it reduced by 34. The number is <br></b>', '51', '50', '45', '40', 'I am not attending this question', '1', 'A'),
(8, '<b> If( 25% of x )= (40% of y), then x:y is equal to <br></b>', '5:7', '8:7', '8:5', '8:9', 'I am not attending this question', '1', 'C'),
(9, '<b> An fruit vendor buys 30 oranges for  Rs. 187.50 .At what price  did he sell  each orange to get a profit  of 12%? <br></b>', 'Rs.7', 'Rs.7.50', 'Rs.8', 'Rs.8.25', 'I am not attending this question', '1', 'A'),
(10, '<b>If  the cost price  of 12 articles to the selling price of 10 articles, then find the profit% in transaction. <br></b>', '15%', '20%', '25%', 'Data insufficient', 'I am not attending this question', '1', 'B'),
(11, '<b>Pure milk costs Rs.20 per litre. After adding water the  milkman sells the mixture at the rate of Rs.18 per litre,thereby  making a profit of 25% .In What ratio does he mix the two? <br></b>', '18:7', '18:5', '12:7', '12:5', 'I am not attending this question', '1', 'A'),
(12, '<b>A sum of Rs.8000 was lent partly at 7% and partly at 9% simple interest. If total annual interest be Rs.620.The ration in which the money was lent at given rates is  <br></b>', '5:3', '1:4', '2:3', '3:4', 'I am not attending this question', '1', 'A'),
(13, '<b>In what time will a sum   double itself at 8% per annum simple interest ? <br></b>', '12 yr ', '10 yr', '12.5 yr', '10.5 yr', 'I am not attending this question', '1', 'C'),
(14, '<b> The average of 15 observations is 20.Average of first 5is 16 and next 7 is 22.If 13th observation is 2 more than 14 and 14th observation  is 2 more than 15th observation. Find the 15th observation <br></b>', '20', '12', '6', '30', 'I am not attending this question', '1', 'A'),
(15, '<b>A person travels 120km in 6h, the next 130 km in 5h  and next 200km in 4h.Find his average speed during the whole journey. <br></b>', '37km/h', '30km/h ', '36km/h', 'Cannot be determined', 'I am not attending this question', '1', 'A'),
(16, '<b>8 men can complete a work in 14days.They started  the work and after 2days 3 men left. In how many days will the work be completed  by the remaining men? <br></b>', '12days', '9 days ', '15 days', 'none of these', 'I am not attending this question', '1', 'D'),
(17, '<b> A and B complete a piece of work in 5 days working together.If A had  worked twice as fast the work  would have been completed in 4 days.In how many days can A alone complete the work ? <br></b>', '20 days ', '18 days', '24 days', '15 days', 'I am not attending this question', '1', 'A'),
(18, '<b>A man rows 25 km downstream and 20 km upstream taking 5h each time .What is the velocity of the current ?<br></b>', '1km/h', '2.5 km/h', '3.5 km/h', 'None of these', 'I am not attending this question', '1', 'D'),
(19, '<b>A walks at 3  km/h and    4 h after his start , b cycles after him at 5km/h.How  far from the start does B catch up with A? <br></b>', '30 km', '34 km', '36km', '38km', 'I am not attending this question', '1', 'A'),
(20, '<b>A train 250m long crosses a platform of  equal length in 50s .Find the speed of the train  <br></b>', '10m/s', '15 m/s', '25m/s', '20m/s', 'I am not attending this question', '1', 'A'),
(21, '<b>The percentage increase in area of a rectangle, if each of its sides is increased by 25% is  <br></b>', '25%', '50%', '54%', '56.25%', 'I am not attending this question', '1', 'D'),
(22, '<b>What will be the area of a semi-Circle whose perimeter is 66cm ?<br></b>', '693cm^2', '646cm^2', '521cm^2', 'none of these', 'I am not attending this question', '1', 'D'),
(23, '<b>Please select the most effective word(s) from the given words to fill in the blank to make the sentence meaningfully complete. The words may seem similar or right but there is only one word that should be selected.In a little-publicized deal, Pepsi Cola has ...... the entire soft drink market in Afghanistan <br></b>', 'occupied', 'conquered', 'swallowed', 'captured', 'I am not attending this question', '1', 'B'),
(24, '<b>Find the correctly spell  words  <br></b>', 'Efficient', 'Treatmeant', 'Beterment', 'Employd', 'I am not attending this question', '1', 'A'),
(25, '<b>What is the synonyms of CANNY ? <br></b>', 'Obstinate', 'Handsome', 'Clever', 'Stout ', 'I am not attending this question', '1', 'C'),
(26, '<b> Which of the following operating system is also known as single user operating system? <br></b>', 'Windows', 'Linux', 'Unix', 'DOS ', 'I am not attending this question', '1', 'D'),
(27, '<b>It is the first program run on a computer ,when the computer boots up <br></b>', 'System software', 'operating System', 'System operations', 'processing system', 'I am not attending this question', '1', 'B'),
(28, '<b>Router operate in which layer of the OSI model?  <br></b>', 'physical layer', 'Data link layer', 'Network layer', 'none of the above', 'I am not attending this question', '1', 'C'),
(29, '<b>Which step is taken first in designing a program?  <br></b>', 'Data validation', 'Input design', 'Task analysis', ' Problem identification', 'I am not attending this question', '1', 'D'),
(30, '<p><b> What is the output of the program? <br> typedef struct data;<br>{<br> int x; <br>sdata *b; <br>}sdata;<br><b></p>', 'Error: Declaration missing \';\'', ' Error: in typedef ', 'No error', 'None of above', 'I am not attending this question', '1', 'A'),
(31, '<p> What is the output of the program? <br>#include < stdio.h > <br>int main() <br>{ <br>char c=48; <br>int i, mask=01; <br>for(i=1; i<=5; i++){ <br><br>printf(%c\"\" c|mask);<br>  <br> mask = mask<<1;<br> } <br> return 0; <br> } <br></b></p>', '12400', '12480', '12500', '12556', 'I am not attending this question', '1', 'B'),
(32, '<b>Pointer is used in <br></b>', 'Direct addressing', 'Indexed Addressing', 'Indexed mode', 'Immediate Addressing', 'I am not attending this question', '1', 'D'),
(33, '<b>An array can be passed in a function in C language through  ? <br></b>', 'Call by value only', 'Call by reference only', 'Both a & b ', 'Call by preference', 'I am not attending this question', '1', 'A'),
(34, '<b>Static variables are sometimes called <br></b>', 'Class variables', 'functional variables', 'dynamic variables', 'auto variables', 'I am not attending this question', '1', 'A'),
(35, '<b>By default any real number in C is treated as  <br></b>', 'a float', 'a double ', 'a long double', 'none of the above', 'I am not attending this question', '1', 'B'),
(36, '<p>What is the output of the following program?<br>main(){ <br>  <br>int i =2;<br> <br>printf (\\n %d %d \"++i,++i);<br> }<br></p>', ' 3 4', '4 3', '4 4', 'none of the above', 'I am not attending this question', '1', 'B'),
(37, '<b>When you omit parameters from a function call, value can be provided by   <br></b>', 'formal parameters', 'reference parameters ', 'overloaded parameters', 'default parameters', 'I am not attending this question', '1', 'A'),
(38, '<b> The feature in object oriented programming that allows the same operation to be carried out differently , depending on the object, is  <br></b>', 'inheritance', 'polymorphism', 'overfunctioning', 'overriding', 'I am not attending this question', '1', 'B'),
(39, '<b>The process of extracting the relevant attributes of an object is known as  <br></b>', ' polymorphism', ' Inheritance', 'Abstraction', 'data hiding ', 'I am not attending this question', '1', 'C'),
(40, '<b>Local variables   <br></b>', 'are created outside a block  ', 'are known only to that block', 'Continue to exist when their block ends', 'Are illegal in C++', 'I am not attending this question', '1', 'B'),
(41, '<b>The JDBC-ODBC bridge is    <br></b>', 'Three tiered', 'Multipread', 'Best of any platform', 'All of the above', 'I am not attending this question', '1', 'A'),
(42, '<b>Queue can be used to implement ?   <br></b>', 'radix sort', 'quick sort', 'recursion ', 'depth first search', 'I am not attending this question', '1', 'A'),
(43, '<b>Which of the following is useful in implementing quick sort?  <br></b>', 'Stack', 'Set', 'List', 'Queue  ', 'I am not attending this question', '1', 'C'),
(44, '<b> A linear list in which elements can be added or removed at either end but not in middle is known as  <br></b>', 'queue', 'deque ', 'stack', 'tree', 'I am not attending this question', '1', 'B'),
(45, '<b>The order of the Binary search algorithm is <br></b>', 'n', 'n^2', 'nlog(n)', 'log(n)', 'I am not attending this question', '1', 'D'),
(46, '<b>In SQL, which of the following is not a data definition language command ?   <br></b>', 'RENAME', 'REVOKE', 'GRANT', 'UPDATE', 'I am not attending this question', '1', 'D'),
(47, '<b> In SQL, which command is used to changes data in a data table?  <br></b>', 'UPDATE', 'INSERT', 'BROWSE', ' APPEND', 'I am not attending this question', '1', 'A'),
(48, '<b>In a relational schema, each tuple is divided into fields called  <br></b>', 'relational', 'domains', 'queries', 'all of this', 'I am not attending this question', '1', 'B'),
(49, '<b>To discard all pending data changes   <br></b>', 'COMMIT', 'ROLLBACK', 'SAVEPOINT LOCK', 'DISCHARGE', 'I am not attending this question', '1', 'B'),
(50, '<b>TRUNCATE statement in SQL is a  <br></b>', 'DML STATEMENT', 'DDL STATEMENT', 'DSL STATEMENT', 'DCL STATEMENT', 'I am not attending this question', '1', 'B'),
(51, '<b>When an array is passed to a method, what does the method receive?<br></b>', 'The reference of the array', 'A copy of the array', 'Length of the array', 'Copy of first element', 'I am not attending this question', '1', 'A'),
(52, '<b>Select the valid statement to declare and initialize an array.<br></b>', 'int[] A = {}', 'int[] A = {1, 2, 3}', 'int[] A = (1, 2, 3)', 'int[][] A = {1,2,3}', 'I am not attending this question', '1', 'B'),
(53, '<b>When is the object created with new keyword?<br></b>', 'At run time', 'At compile time', 'Depends on the code', 'None', 'I am not attending this question', '1', 'A'),
(54, '<b>Identify the corrected definition of a package.<br></b>', 'A package is a collection of editing tools', 'A package is a collection of classes', 'A package is a collection of classes and interfaces', 'A package is a collection of interfaces', 'I am not attending this question', '1', 'C'),
(55, '<b>Identify the keyword among the following that makes a variable belong to a class,rather than being defined for each instance of the class.<br></b>', 'final', 'static', 'volatile', 'abstract', 'I am not attending this question', '1', 'B'),
(56, '<b>In which of the following is toString() method defined?<br></b>', 'java.lang.Object', 'java.lang.String', 'java.lang.util', 'None', 'I am not attending this question', '1', 'A'),
(57, '<b>compareTo() returns<br></b>', 'True', 'False', 'An int value', 'None', 'I am not attending this question', '1', 'C'),
(58, '<b>To which of the following does the class string belong to.<br></b>', 'java.lang', 'java.awt', 'java.applet', 'java.string', 'I am not attending this question', '1', 'A'),
(59, '<b>Total constructor string class have?<br></b>', '3', '7', '13', '20', 'I am not attending this question', '1', 'C'),
(60, '<b>Output of Math.floor(3.6)?<br></b>', '3', '3.0', '4', '4.0', 'I am not attending this question', '1', 'B');
